noncompliant:
// Redundant qualifiers in enum declarations
enum class Color : const long int { // Noncompliant - const is ignored
    Red = 0xff0000,
    Green = 0x00ff00,
    Blue = 0x0000ff
};

enum class Size : volatile char { // Noncompliant - volatile is ignored
    Small = 1,
    Medium = 2,
    Large = 3
};

enum Status : const volatile int { // Noncompliant - both are redundant
    Active,
    Inactive
};

compliant:
// Clean enum declarations
enum class Color : long int { // Compliant - no unnecessary qualifiers
    Red = 0xff0000,
    Green = 0x00ff00,
    Blue = 0x0000ff
};

enum class Size : char { // Compliant
    Small = 1,
    Medium = 2,
    Large = 3
};

enum Status : int { // Compliant
    Active,
    Inactive
};
